package org.expenses.utils;import java.io.FileInputStream;import java.io.IOException;import java.util.Properties;public class ReadProperties {    private static final Properties properties = new Properties();    public static String getProperty(String propFile, String key){        try(FileInputStream fis = new FileInputStream(propFile)) {            properties.load(fis);            return properties.getProperty(key);        } catch (IOException e) {            throw new RuntimeException(e);        }    }}